esqlQuery.esql:
FROM metrics-airflow.otel-default*
| WHERE data_stream.dataset == "airflow.otel"
// Count scheduler heartbeats in the rule's time window
| STATS hb_count = COUNT(airflow.scheduler_heartbeat), total_docs = COUNT(*)
// Alert when we have Airflow activity but fewer than 5 heartbeats
// Adjust threshold (5) for your scheduler heartbeat cadence
| WHERE total_docs > 10 AND hb_count < 5
